  id: number
  slug: string
  name: string
  price: number
  image: string
  category: string
  featured?: boolean
  new?: boolean
  rating?: number
}

export function ProductCard(product: ProductCardProps) {
  return (
    <div className="group relative">
      <WishlistButton product={product} />
      <Link href={`/producto/${product.slug}`}>
        <div className={`rounded-xl overflow-hidden bg-surface card-hover ${product.featured ? "border-2 border-accent" : "border border-border"}`}>
          <div className="h-48 bg-gradient-to-br from-surface-light to-surface flex items-center justify-center p-5">
            <div className="w-full h-full flex items-center justify-center text-primary text-5xl opacity-20 select-none">✦</div>
            {product.new && (
              <span className="absolute top-3 right-12 bg-accent text-accent-foreground text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider">Nuevo</span>
            )}
